import type { TmplAstElement } from '@angular-eslint/bundled-angular-compiler';
import { getOriginalAttributeName } from './get-original-attribute-name';
import { getAttributeValue } from './get-attribute-value';

export function isDisabledElement(node: TmplAstElement): boolean {
  const attributesInputs = [...node.attributes, ...node.inputs];
  const disabledAttr = attributesInputs.find(
    (attr) => getOriginalAttributeName(attr) === 'disabled',
  );
  const disabledValue = getAttributeValue(node, 'disabled');
  const isHTML5Disabled = disabledAttr && disabledValue !== undefined;
  if (isHTML5Disabled) {
    return true;
  }

  const isAriaDisabled =
    String(getAttributeValue(node, 'aria-disabled')).toLowerCase() === 'true';
  if (isAriaDisabled) {
    return true;
  }

  return false;
}

export const isNonNullable = <T>(val: T): val is NonNullable<T> => {
  return val !== undefined && val !== null;
};

export const isReactRenderable = <T>(val: T): val is Exclude<NonNullable<T>, false | ''> => {
  return isNonNullable(val) && val !== false && val !== '';
};

export const isNumber = (val: any): val is number => {
  return typeof val === 'number' && !Number.isNaN(val);
};

export const isString = (val: any): val is string => {
  return typeof val === 'string';
};

export const isPlainObject = <T extends object = object>(val: any): val is T => {
  return val !== null && typeof val === 'object';
};

export const isFunction = (val: any): val is (...args: any[]) => any => {
  return typeof val === 'function';
};

export const isThenable = <T>(val?: PromiseLike<T>): val is PromiseLike<T> => {
  return isNonNullable(val) && isFunction(val.then);
};

export const isPrimitive = (val: any) => {
  return (typeof val !== 'object' && !isFunction(val)) || val === null;
};

export const isTransitionEvent = (event: Event): event is TransitionEvent => {
  return isPlainObject(event) && 'propertyName' in event && isString(event.propertyName);
};

