export interface NpmPackage {
  name: string
  description: string
  version: string
  keywords: string[]
  date: string
  links: {
    npm: string
    homepage: string
    repository: string
  }
}

interface NpmRegistryResponse {
  objects: { package: NpmPackage }[]
}

export async function fetchNpmPackages(pattern: string): Promise<Choice[]> {
  const registryLink = (pattern: string) =>
    `https://registry.npmjs.com/-/v1/search?text=${pattern}&size=35`

  const terminalColumns = process.stdout?.columns || 80

  try {
    const result = await fetch(registryLink(pattern))
      .then(res => res.json()) as NpmRegistryResponse

    return result.objects.map(({ package: pkg }) => ({
      title: formatPackageWithUrl(
        `${pkg.name.padEnd(30, ' ')} ${styleText('blue', `v${pkg.version}`)}`,
        pkg.links.repository ?? pkg.links.npm,
        terminalColumns,
      ),
      value: pkg,
    }))
  }
  catch {
    console.error('Error when fetching npm registry')
    process.exit(1)
  }
}

import { toArray } from '@antfu/utils'

function escapeRegExp(str: string) {
  return str.replace(/[.+?^${}()|[\]\\]/g, '\\$&') // $& means the whole matched string
}

export function filterToRegex(str: string) {
  if (str.startsWith('/')) {
    const endIndex = str.lastIndexOf('/')
    const regexp = str.substring(1, endIndex)
    const flags = str.substring(endIndex + 1, str.length)
    return new RegExp(regexp, flags)
  }
  return new RegExp(`^${escapeRegExp(str).replace(/\*+/g, '.*?')}$`)
}

export function parseFilter(str?: string | string[], defaultValue = true): ((name: string) => boolean) {
  if (!str || str.length === 0)
    return () => defaultValue

  const regex = toArray(str).flatMap(i => i.split(',')).map(filterToRegex)

  return (name) => {
    for (const reg of regex) {
      if (reg.test(name))
        return true
    }
    return false
  }
}

export function createDependenciesFilter(include?: string | string[], exclude?: string | string[]) {
  const i = parseFilter(include, true)
  const e = parseFilter(exclude, false)
  return (name: string) => !e(name) && i(name)
}

import type { SystemContext } from "@chakra-ui/react"
import { pretty } from "./pretty.js"
import { capitalize, unionType } from "./shared.js"

export async function generateTokens(sys: SystemContext) {
  const { allTokens, tokenMap, colorPaletteMap, categoryMap } = sys.tokens

  const isTokenEmpty = allTokens.length === 0

  const set = new Set<string>()

  set.add(
    `export type Token = ${
      isTokenEmpty ? "string" : unionType(Array.from(tokenMap.keys()))
    }`,
  )

  const result = new Set<string>(["export type Tokens = {"])

  if (isTokenEmpty) {
    result.add("[token: string]: string")
  } else {
    const colorPaletteKeys = Array.from(colorPaletteMap.keys())

    if (colorPaletteKeys.length) {
      set.add(`export type ColorPalette = ${unionType(colorPaletteKeys)}`)
    }

    for (const [key, value] of categoryMap.entries()) {
      const typeName = capitalize(key)
      set.add(`export type ${typeName}Token = ${unionType(value.keys())}`)
      result.add(`\t\t${key}: ${typeName}Token`)
    }
  }

  result.add("} & { [token: string]: never }")

  set.add(Array.from(result).join("\n"))

  return pretty(Array.from(set).join("\n\n"))
}

import * as git from "@changesets/git";
import { Package, Tool } from "@manypkg/get-packages";

export async function getUntaggedPackages(
  packages: Package[],
  cwd: string,
  tool: Tool
) {
  const packageWithTags = await Promise.all(
    packages.map(async (pkg) => {
      const tagName =
        tool === "root"
          ? `v${pkg.packageJson.version}`
          : `${pkg.packageJson.name}@${pkg.packageJson.version}`;
      const isMissingTag = !(
        (await git.tagExists(tagName, cwd)) ||
        (await git.remoteTagExists(tagName))
      );

      return { pkg, isMissingTag };
    })
  );

  const untagged: Array<{ name: string; newVersion: string }> = [];

  for (const packageWithTag of packageWithTags) {
    if (packageWithTag.isMissingTag) {
      untagged.push({
        name: packageWithTag.pkg.packageJson.name,
        newVersion: packageWithTag.pkg.packageJson.version,
      });
    }
  }

  return untagged;
}

