import { CommandConfigOptions } from "../project";

//  * Only own keys, not inherited
export function defaultOptions<T extends CommandConfigOptions>(...sources: any[]): T {
  const options: CommandConfigOptions = {};

  for (const source of sources) {
    if (source != null) {
      for (const key of Object.keys(source)) {
        // TODO: refactor to address type issues
        // eslint-disable-next-line @typescript-eslint/ban-ts-comment
        // @ts-ignore
        if (options[key] === undefined) {
          // TODO: refactor to address type issues
          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
          // @ts-ignore
          options[key] = source[key];
        }
      }
    }
  }

  return options as T;
}

import type { BrandVariants, Theme } from '@fluentui/react-components';
import { brandRamp } from './getOverridableTokenBrandColors';

export const getBrandValues = (
  brand: BrandVariants,
  overrideList: Partial<Theme>,
  name: string,
  spacer: string,
): string => {
  const hexToBrand: Record<string, string> = {};

  brandRamp.map(i => {
    hexToBrand[brand[i]] = name + '[' + `${i as number}` + ']';
    return;
  });

  const stringOverrideList = overrideList as Record<string, string>;

  return (
    Object.keys(overrideList).map(token => {
      return '\n' + spacer + token + ': ' + hexToBrand[stringOverrideList[token]];
    }) + '\n'
  );
};

export const objectToString = (input: Record<string, string>, spacer: string): string => {
  return (
    Object.keys(input).map(key => {
      return '\n' + spacer + key + ': "' + input[key].toUpperCase() + '"';
    }) + '\n'
  );
};

