import {
    createCodeFixActionWithoutFixAll,
    registerCodeFix,
} from "../_namespaces/ts.codefix.js";
import {
    Diagnostics,
    findAncestor,
    getTokenAtPosition,
    isCallExpression,
    textChanges,
} from "../_namespaces/ts.js";

const fixId = "removeAccidentalCallParentheses";
const errorCodes = [
    Diagnostics.This_expression_is_not_callable_because_it_is_a_get_accessor_Did_you_mean_to_use_it_without.code,
];
registerCodeFix({
    errorCodes,
    getCodeActions(context) {
        const callExpression = findAncestor(getTokenAtPosition(context.sourceFile, context.span.start), isCallExpression);
        if (!callExpression) {
            return undefined;
        }
        const changes = textChanges.ChangeTracker.with(context, t => {
            t.deleteRange(context.sourceFile, { pos: callExpression.expression.end, end: callExpression.end });
        });
        return [createCodeFixActionWithoutFixAll(fixId, changes, Diagnostics.Remove_parentheses)];
    },
    fixIds: [fixId],
});

import type { Action, ActionStatus } from '@moonrepo/types';
import { getDurationInMillis } from './time';

export function getIconForStatus(status: ActionStatus): string {
	// Use exhaustive checks!
	switch (status) {
		case 'cached':
			return '🟪';
		case 'cached-from-remote':
			return '🟦';
		case 'failed':
		case 'aborted':
		case 'timed-out':
			return '🟥';
		case 'invalid':
			return '🟨';
		case 'passed':
			return '🟩';
		case 'running':
		case 'skipped':
			return '⬛️';
	}

	return '⬜️';
}

export function hasFailed(status: ActionStatus): boolean {
	return status === 'failed' || status === 'aborted' || status === 'timed-out';
}

export function hasPassed(status: ActionStatus): boolean {
	return status === 'passed' || status === 'cached' || status === 'cached-from-remote';
}

export function isFlaky(action: Action): boolean {
	return action.flaky ?? false;
}

export function isSlow(action: Action, slowThreshold: number): boolean {
	if (!action.duration) {
		return false;
	}

	const millis = getDurationInMillis(action.duration);
	// eslint-disable-next-line no-magic-numbers
	const threshold = slowThreshold * 1000; // In seconds

	return millis > threshold;
}

import { existsSync, mkdirSync } from 'node:fs';
import { join } from 'node:path';
import type { I18nOptions } from '../models';

export function ensureOutputPaths(
  baseOutputPath: string,
  i18n: I18nOptions
): Map<string, string> {
  const outputPaths = getLocaleOutputPaths(i18n);

  for (const [, outputPath] of outputPaths) {
    const fullPath = join(baseOutputPath, outputPath);
    if (!existsSync(fullPath)) {
      mkdirSync(fullPath, { recursive: true });
    }
  }

  return outputPaths;
}

export function getLocaleOutputPaths(i18n: I18nOptions): Map<string, string> {
  const outputPaths: [string, string][] = i18n.shouldInline
    ? [...i18n.inlineLocales].map((l) => [
        l,
        i18n.flatOutput ? '' : i18n.locales[l].subPath,
      ])
    : [['', '']];

  return new Map(outputPaths);
}

import {ActionBase, ActionType} from './base'

export default class SimpleAction extends ActionBase {
  public type: ActionType = 'simple'

  protected _pause(icon?: string): void {
    if (icon) this._updateStatus(icon)
    else this._flush()
  }

  protected _resume(): void {
    // Not implemented
  }

  protected _start(): void {
    if (!this.task) return
    this._render(this.task.action, this.task.status)
  }

  protected _stop(status: string): void {
    if (!this.task) return
    this._updateStatus(status, this.task.status, true)
  }

  protected _updateStatus(status: string, prevStatus?: string, newline = false): void {
    if (!this.task) return
    if (this.task.active && !prevStatus) this._write(this.std, ` ${status}`)
    else this._write(this.std, `${this.task.action}... ${status}`)
    if (newline || !prevStatus) this._flush()
  }

  private _flush() {
    this._write(this.std, '\n')
    this._flushStdout()
  }

  private _render(action: string, status?: string) {
    if (!this.task) return
    if (this.task.active) this._flush()
    this._write(this.std, status ? `${action}... ${status}` : `${action}...`)
  }
}

import type { ScopeLog } from '@pnpm/core-loggers'
import * as Rx from 'rxjs'
import { map, take } from 'rxjs/operators'

const COMMANDS_THAT_REPORT_SCOPE = new Set([
  'install',
  'link',
  'prune',
  'rebuild',
  'remove',
  'unlink',
  'update',
  'run',
  'test',
])

export function reportScope (
  scope$: Rx.Observable<ScopeLog>,
  opts: {
    isRecursive: boolean
    cmd: string
  }
): Rx.Observable<Rx.Observable<{ msg: string }>> {
  if (!COMMANDS_THAT_REPORT_SCOPE.has(opts.cmd)) {
    return Rx.NEVER
  }
  return scope$.pipe(
    take(1),
    map((log) => {
      if (log.selected === 1) {
        return Rx.NEVER
      }
      let msg = 'Scope: '

      if (log.selected === log.total) {
        msg += `all ${log.total}`
      } else {
        msg += `${log.selected}`
        if (log.total) {
          msg += ` of ${log.total}`
        }
      }

      if (log.workspacePrefix) {
        msg += ' workspace projects'
      } else {
        msg += ' projects'
      }

      return Rx.of({ msg })
    })
  )
}

