import Module from 'node:module';

export const getOriginalFilePath = (
	request: string,
) => {
	if (!request.startsWith('data:text/javascript,')) {
		return;
	}

	const queryIndex = request.indexOf('?');
	if (queryIndex === -1) {
		return;
	}

	const searchParams = new URLSearchParams(request.slice(queryIndex + 1));
	const filePath = searchParams.get('filePath');
	if (filePath) {
		return filePath;
	}
};

export const interopCjsExports = (
	request: string,
) => {
	const filePath = getOriginalFilePath(request);
	if (filePath) {
		// The CJS module cache needs to be updated with the actual path for export parsing to work
		// https://github.com/nodejs/node/blob/v22.2.0/lib/internal/modules/esm/translators.js#L338
		Module._cache[filePath] = Module._cache[request];
		delete Module._cache[request];
		request = filePath;
	}
	return request;
};

import { isPlainObject as _iPO } from '../core/rtkImports'

// remove type guard
const isPlainObject: (_: any) => boolean = _iPO

export function copyWithStructuralSharing<T>(oldObj: any, newObj: T): T
export function copyWithStructuralSharing(oldObj: any, newObj: any): any {
  if (
    oldObj === newObj ||
    !(
      (isPlainObject(oldObj) && isPlainObject(newObj)) ||
      (Array.isArray(oldObj) && Array.isArray(newObj))
    )
  ) {
    return newObj
  }
  const newKeys = Object.keys(newObj)
  const oldKeys = Object.keys(oldObj)

  let isSameObject = newKeys.length === oldKeys.length
  const mergeObj: any = Array.isArray(newObj) ? [] : {}
  for (const key of newKeys) {
    mergeObj[key] = copyWithStructuralSharing(oldObj[key], newObj[key])
    if (isSameObject) isSameObject = oldObj[key] === mergeObj[key]
  }
  return isSameObject ? oldObj : mergeObj
}

import { ExtensionPriority } from '@remirror/core-constants';
import type { Handler } from '@remirror/core-types';

import { extension, PlainExtension } from '../extension';
import type { StateUpdateLifecycleProps } from '../types';

export interface DocChangedOptions {
  docChanged?: Handler<(props: StateUpdateLifecycleProps) => void>;
}

@extension<DocChangedOptions>({
  handlerKeys: ['docChanged'],
  handlerKeyOptions: {
    docChanged: { earlyReturnValue: false }, // Execute all handlers, even if one returns false
  },
  defaultPriority: ExtensionPriority.Lowest,
})
export class DocChangedExtension extends PlainExtension<DocChangedOptions> {
  get name() {
    return 'docChanged' as const;
  }

  onStateUpdate(props: StateUpdateLifecycleProps): void {
    const { firstUpdate, transactions, tr } = props;

    if (firstUpdate) {
      return;
    }

    if ((transactions ?? [tr]).some((tr) => tr?.docChanged)) {
      this.options.docChanged(props);
    }
  }
}

